 1	import React from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { Button, ButtonVariant } from '@patternfly/react-core';
 7	
 8	import { RDPServiceNotConfiguredProps } from '../utils/types';
 9	
10	import RDPServiceModal from './RDPServiceModal';
11	
12	import './rdp-service.scss';
13	
14	const RDPServiceNotConfigured: React.FC<RDPServiceNotConfiguredProps> = ({ vm, vmi }) => {
15	  const { t } = useKubevirtTranslation();
16	  const { createModal } = useModal();
17	  return (
18	    <Trans ns="plugin__kubevirt-plugin" t={t}>
19	      <span>
20	        This is a Windows VirtualMachine but no Service for the RDP (Remote Desktop Protocol) can be
21	        found.
22	      </span>
23	      <br />
24	      <span>
25	        For better experience accessing Windows console, it is recommended to use the RDP.
26	        <Button
27	          className="kv-create-rdp-service-button"
28	          onClick={() => createModal((props) => <RDPServiceModal vm={vm} vmi={vmi} {...props} />)}
29	          variant={ButtonVariant.secondary}
30	        >
31	          Create RDP Service
32	        </Button>
33	      </span>
34	    </Trans>
35	  );
36	};
37	
38	export default RDPServiceNotConfigured;

